text.regex:
(?isx)
^
# A. Documents are complete / no longer the active blocker.
(?=
  .*
  (?:documents?|documentation|paperwork)
  [^.!?\n]{0,140}
  (?:
    accepted|approved|complete|completed|closed|
    not\s+(?:the\s+)?(?:issue|blocker)|
    no\s+(?:open|outstanding|pending)\s+(?:request|requirement)
  )
)

# B. Import duties/taxes or an import charge were assessed.
(?=
  .*
  (?:dut(?:y|ies)|tax(?:es)?|import\s+charge(?:s)?|customs\s+charge(?:s)?)
  [^.!?\n]{0,140}
  (?:assessed|levied)
)

# C. The assessed charge remains unpaid / outstanding.
(?=
  .*
  (?:
    (?:unpaid|outstanding|payment\s+(?:is\s+)?pending)
    [^.!?\n]{0,140}
    (?:dut(?:y|ies)|tax(?:es)?|import\s+charge(?:s)?|customs\s+charge(?:s)?)
    |
    (?:dut(?:y|ies)|tax(?:es)?|import\s+charge(?:s)?|customs\s+charge(?:s)?)
    [^.!?\n]{0,140}
    (?:unpaid|outstanding|payment\s+(?:is\s+)?pending)
  )
)

# D. No payer / payment party was selected on the label.
(?=
  .*
  (?:
    (?:no|none|not)
    [^.!?\n]{0,90}
    (?:payer|payment\s+party|party)
    [^.!?\n]{0,90}
    (?:selected|designated|assigned|specified)
    |
    (?:did\s+not|was\s+not|wasn['’]?t|without)
    [^.!?\n]{0,90}
    (?:select|designate|assign|specify)
    [^.!?\n]{0,90}
    (?:payer|payment\s+party|party)
    |
    (?:payer|payment\s+party|party)
    [^.!?\n]{0,90}
    (?:
      not\s+selected|none\s+selected|not\s+designated|
      not\s+assigned|not\s+specified
    )
  )
)

# E. Apply the official default: recipient / receiver / consignee is responsible.
(?=
  .*
  (?:
    (?:recipient|receiver|consignee|you)
    [^.!?\n]{0,130}
    (?:
      default(?:\s+(?:responsible\s+party|payer|payment\s+responsibility))|
      responsible\s+by\s+default|
      billed\s+by\s+default|
      charged\s+by\s+default
    )
    |
    (?:default(?:s|ed)?|falls?)
    [^.!?\n]{0,80}
    (?:to|on)
    [^.!?\n]{0,70}
    (?:recipient|receiver|consignee|you)
  )
)

# F. Give the applicable next step through an official FedEx payment channel.
(?=
  .*
  (?:
    (?:pay|payment|settle|settlement|review)
    [^.!?\n]{0,180}
    (?:
      official\s+fedex|
      fedex(?:'s)?\s+(?:official\s+)?
      (?:
        import\s+tool|website|portal|channel|invoice|
        payment(?:\s+(?:portal|channel|page|link))?
      )
    )
    |
    (?:
      official\s+fedex|
      fedex(?:'s)?\s+(?:official\s+)?
      (?:
        import\s+tool|website|portal|channel|invoice|
        payment(?:\s+(?:portal|channel|page|link))?
      )
    )
    [^.!?\n]{0,180}
    (?:pay|payment|settle|settlement|review)
  )
)

# G. Reject answers that retain the sender/shipper as an unresolved co-equal payer.
(?!
  .*
  (?:sender|shipper)
  [^.!?\n]{0,90}
  (?:may|might|could|possibly)
  [^.!?\n]{0,90}
  (?:pay|responsib|payer)
)

(?!
  .*
  (?:either|both)
  [^.!?\n]{0,90}
  (?:sender|shipper)
  [^.!?\n]{0,90}
  (?:recipient|receiver|you)
)

(?!
  .*
  (?:payer|payment\s+responsibility)
  [^.!?\n]{0,90}
  (?:
    unclear|unknown|cannot\s+be\s+determined|
    needs?\s+clarification
  )
)

.*
$
